function getTileHitAreaStyle() {
  const padding = shapeSortConfig.dragPaddingPx;
  return {
    margin: `${padding}px`,
    minWidth: `${shapeSortConfig.tileSizePx + padding * 2}px`,
    minHeight: `${shapeSortConfig.tileSizePx + padding * 2}px`,
  };
}

window.shapeSortGetTileHitAreaStyle = getTileHitAreaStyle;

